<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">151</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">         pr_debug</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;failed to register powercap control_type.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
